mapper.select:
SELECT id, name, device_number, category_id, status, approval_mode_override, image_url, description, purchase_date, location, status_change_reason, created_at, updated_at FROM device WHERE status != 'DELETED'
AND category_id = #{categoryId}
ORDER BY created_at DESC

mapper.update:
UPDATE device
SET status = #{newStatus},
    status_change_reason = #{reason},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{deviceId}
  AND status = #{expectedStatus}
